```

### 현재 추정 Repository 구조

**파일 위치:** `domain/src/main/kotlin/com/maum/backend/repository/follow/FollowRepository.kt`

```kotlin
// [BEFORE] - 인덱스 없는 단순 조회
interface FollowRepository : JpaRepository<FollowEntity, String> {
    // 병목 원인 4: follower_id 인덱스 없음 -> Full Scan
    fun findByFollowerId(followerId: String): List<FollowEntity>
}
```

### 현재 추정 Service 구조

**파일 위치:** `api/src/main/kotlin/com/maum/backend/service/follow/FollowService.kt`

```kotlin
// [BEFORE] - N+1 쿼리가 발생하는 서비스 로직
@Service
class FollowService(
    private val followRepository: FollowRepository,
    private val userRepository: UserRepository,
) {
    fun getFollowingList(userId: String): List<FollowingDto> {
        // 쿼리 1: follow 목록 조회 (예: 200건)
        val follows = followRepository.findByFollowerId(userId)

        // 병목 원인 5: N+1 - follows 200건 * 각 1쿼리 = 200쿼리 추가 발생
        return follows.map { follow ->
            val user = userRepository.findById(follow.followingId).orElseThrow()
            // 병목 원인 6: 프로필 조회도 별도 쿼리
            val profile = profileRepository.findByUserId(user.id)

            FollowingDto(
                userId = user.id,
                nickname = user.nickname,
                profileImageUrl = profile?.imageUrl,
                isFollowingBack = followRepository.existsByFollowerIdAndFollowingId(
                    user.id, userId  // 병목 원인 7: 맞팔 확인도 N번 추가
                )
            )
        }
    }
}
```

