### 개선 5: Entity 관계 정리 (LAZY + 단방향)

**파일 위치:** `domain/src/main/kotlin/com/maum/backend/entity/follow/FollowEntity.kt`

```kotlin
// [AFTER] - EAGER 제거, 단방향 유지, 양방향 컬렉션 제거
@Entity
@Table(
    catalog = "maum",
    name = "follow",
    indexes = [
        Index(name = "idx_follow_follower_id", columnList = "follower_id, created_at DESC"),
        Index(name = "idx_follow_following_id", columnList = "following_id, created_at DESC"),
    ],
    uniqueConstraints = [
        UniqueConstraint(name = "uk_follow", columnNames = ["follower_id", "following_id"])
    ]
)
class FollowEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val followerId: String,
    val followingId: String,

    // [AFTER] - LAZY 명시, 직접 접근 최소화
    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "follower_id", referencedColumnName = "id",
                insertable = false, updatable = false)
    val follower: UserEntity? = null,

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "following_id", referencedColumnName = "id",
                insertable = false, updatable = false)
    val following: UserEntity? = null,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),
)
